/**
 * VELVIA CHARTS ENGINE
 * Handles parsing and rendering of dynamic Plotly graphs from LLM output.
 */

function renderDynamicChart(containerElement, chartJsonString) {
    try {
        // Sanitize the JSON string to remove markdown code blocks if the LLM included them
        let cleanedJsonString = chartJsonString.replace(/```json/gi, '').replace(/```/g, '').trim();
        
        // Fix invalid JSON escape sequences often generated by LLMs trying to escape markdown inside JSON strings
        cleanedJsonString = cleanedJsonString.replace(/\\\*/g, '*'); // Fix A\* -> A*
        cleanedJsonString = cleanedJsonString.replace(/\\_/g, '_'); // Fix \_ -> _
        cleanedJsonString = cleanedJsonString.replace(/\\'/g, "'"); // Fix \' -> '
        
        const chartObj = JSON.parse(cleanedJsonString);
        
        const chartDiv = document.createElement('div');
        chartDiv.className = 'my-4 w-full h-80 rounded-xl overflow-hidden border border-purple-500/30 bg-black/40';
        containerElement.appendChild(chartDiv);
        
        // Apply Cyberpunk Dark Theme styles natively to Plotly layout
        if (!chartObj.layout) chartObj.layout = {};
        chartObj.layout.paper_bgcolor = 'rgba(0,0,0,0)';
        chartObj.layout.plot_bgcolor = 'rgba(0,0,0,0)';
        chartObj.layout.font = { color: '#ffffff', family: "'Inter', sans-serif" };
        
        // Optional: color adjustments for axes if not provided
        if (!chartObj.layout.xaxis) chartObj.layout.xaxis = {};
        if (!chartObj.layout.yaxis) chartObj.layout.yaxis = {};
        chartObj.layout.xaxis.gridcolor = 'rgba(255,255,255,0.1)';
        chartObj.layout.yaxis.gridcolor = 'rgba(255,255,255,0.1)';
        chartObj.layout.xaxis.zerolinecolor = 'rgba(255,255,255,0.2)';
        chartObj.layout.yaxis.zerolinecolor = 'rgba(255,255,255,0.2)';

        // Ensure responsive
        const config = { responsive: true, displayModeBar: false };
        
        Plotly.newPlot(chartDiv, chartObj.data, chartObj.layout, config);
    } catch (e) {
        console.error("VELVIA CHARTS ERROR: Failed to render dynamic chart", e);
        const errorDiv = document.createElement('div');
        errorDiv.className = 'text-red-500 text-xs italic mt-2 p-2 border border-red-500/30 rounded';
        errorDiv.innerText = "[Neural Chart Extraction Failed]";
        containerElement.appendChild(errorDiv);
    }
}
